  'about-us.html': {
    externalScripts: [],
    inlineScripts: [
      "(function() {\n    'use strict';\n\n    const getElement = (selector) => document.querySelector(selector);\n    const getElements = (selector) => document.querySelectorAll(selector);\n\n    function handlePageLoad() {\n        const loader = getElement('#orion-loader');\n        if (loader) {\n            window.addEventListener('load', () => {\n                loader.classList.add('hidden');\n                loader.addEventListener('transitionend', () => loader.remove());\n            }, { once: true });\n        }\n    }\n\n    function setupNavbar() {\n        const navbarContainer = getElement('#navbar-container');\n        const mobileMenuButton = getElement('#mobile-menu-button');\n        const mobileMenu = getElement('#mobile-menu');\n        const navbar = getElement('#main-navbar');\n        const navbarLogo = getElement('#navbar-logo-img');\n\n        if (mobileMenuButton && mobileMenu) {\n            mobileMenuButton.addEventListener('click', () => {\n                const isExpanded = mobileMenuButton.getAttribute('aria-expanded') === 'true';\n                mobileMenuButton.setAttribute('aria-expanded', String(!isExpanded));\n                mobileMenuButton.classList.toggle('is-active');\n                mobileMenu.classList.toggle('hidden');\n                mobileMenu.classList.toggle('is-open');\n            });\n        }\n\n        if (navbar && navbarLogo && navbarContainer) {\n            const logoDefault = 'img/full_Logoblack.png';\n            const logoScrolled = 'img/full_logowhite.png';\n            new Image().src = logoScrolled;\n\n            const handleScroll = () => {\n                const isScrolled = window.scrollY > 20;\n\n                navbar.classList.toggle('navbar-scrolled', isScrolled);\n                navbar.classList.toggle('rounded-full', isScrolled);\n                navbarContainer.classList.toggle('p-2', isScrolled);\n                navbarContainer.classList.toggle('sm:p-3', isScrolled);\n\n                if (navbarLogo) {\n                    navbarLogo.src = isScrolled ? logoScrolled : logoDefault;\n                }\n            };\n\n            // Set initial state on page load to ensure correct appearance\n            handleScroll();\n\n            window.addEventListener('scroll', handleScroll, { passive: true });\n        }\n    }\n\n    function setupParallax() {\n        const bgAssets = getElements('.bg-ev-asset');\n        if (bgAssets.length === 0) return;\n\n        const handleScroll = () => {\n            const scrollY = window.pageYOffset;\n            bgAssets.forEach(asset => {\n                const speed = parseFloat(asset.dataset.speed || '0');\n                const yPos = -scrollY * speed;\n                asset.style.transform = `translateY(${yPos}px)`;\n            });\n        };\n        window.addEventListener('scroll', handleScroll, { passive: true });\n    }\n\n    function setupComparisonSlider() {\n        const sliderContainer = getElement('.comparison-slider');\n        if (!sliderContainer) return;\n\n        const handle = sliderContainer.querySelector('.slider-handle');\n        const topImageContainer = sliderContainer.querySelector('div[style*=\"clip-path\"]');\n        let isDragging = false;\n\n        const moveSlider = (clientX) => {\n            const rect = sliderContainer.getBoundingClientRect();\n            let position = ((clientX - rect.left) / rect.width) * 100;\n            position = Math.max(0, Math.min(100, position));\n\n            handle.style.left = `${position}%`;\n            topImageContainer.style.clipPath = `inset(0 ${100 - position}% 0 0)`;\n        };\n\n        const startDrag = (e) => {\n            e.preventDefault();\n            isDragging = true;\n        };\n        const stopDrag = () => { isDragging = false; };\n        const onDrag = (e) => {\n            if (!isDragging) return;\n            const clientX = e.touches ? e.touches[0].clientX : e.clientX;\n            moveSlider(clientX);\n        };\n\n        handle.addEventListener('mousedown', startDrag);\n        handle.addEventListener('touchstart', startDrag, { passive: false });\n        window.addEventListener('mouseup', stopDrag);\n        window.addEventListener('touchend', stopDrag);\n        window.addEventListener('mousemove', onDrag);\n        window.addEventListener('touchmove', onDrag, { passive: false });\n    }\n\n    function setupScrollAnimations() {\n        const animatedElements = getElements('.icon-card, .comparison-slider, .dark-cta-section');\n        if (animatedElements.length === 0) return;\n\n        const observer = new IntersectionObserver((entries, observer) => {\n            entries.forEach(entry => {\n                if (entry.isIntersecting) {\n                    entry.target.classList.add('is-visible');\n                    observer.unobserve(entry.target);\n                }\n            });\n        }, { threshold: 0.1 });\n\n        animatedElements.forEach(el => observer.observe(el));\n    }\n\n    function initialize() {\n        handlePageLoad();\n        setupNavbar();\n        setupParallax();\n        setupComparisonSlider();\n        setupScrollAnimations();\n    }\n\n    if (document.readyState === 'loading') {\n        document.addEventListener('DOMContentLoaded', initialize);\n    } else {\n        initialize();\n    }\n})();",
    ],
  },
