      "document.addEventListener('DOMContentLoaded', () => {\n        // --- 1. LOADER ANIMATION ---\n        const loader = document.getElementById('custom-loader');\n        const loaderBar = document.getElementById('loader-bar');\n        const loaderLogo = document.getElementById('loader-logo');\n        const blindTop = document.getElementById('loader-blind-top');\n        const blindBottom = document.getElementById('loader-blind-bottom');\n        const loaderContent = document.getElementById('loader-content');\n\n        const tl = gsap.timeline({\n            defaults: { ease: \"power3.inOut\" },\n            onComplete: () => {\n                loader.style.display = 'none';\n\n                // Show Content\n                gsap.to('.reveal-element', {\n                    y: 0,\n                    opacity: 1,\n                    duration: 0.8,\n                    stagger: 0.15,\n                    ease: \"power2.out\"\n                });\n\n                // Show Nav\n                gsap.to(['#dynamic-logo', '#dynamic-sidebar-btn'], {\n                    opacity: 1,\n                    duration: 0.5,\n                    delay: 0.2\n                });\n            }\n        });\n\n        tl.to(loaderBar, { width: \"100%\", duration: 1.2, ease: \"power2.inOut\" })\n          .to(loaderBar, { backgroundColor: \"#16a34a\", duration: 0.1 })\n          .to(loaderLogo, { scale: 20, duration: 0.6, ease: \"expo.in\" })\n          .to(loaderLogo, { opacity: 0, duration: 0.2 }, \"-=0.2\")\n          .set(loaderContent, { opacity: 0 })\n          .to(blindTop, { scaleY: 0, duration: 0.8, ease: \"power4.inOut\" }, \"-=0.3\")\n          .to(blindBottom, { scaleY: 0, duration: 0.8, ease: \"power4.inOut\" }, \"<\");\n\n\n        // --- 2. MOBILE MENU LOGIC ---\n        const menuBtn = document.getElementById('dynamic-sidebar-btn');\n        const menuOverlay = document.getElementById('mobile-menu-overlay');\n        const menuBackdrop = document.getElementById('mobile-menu-backdrop');\n        const menuClose = document.getElementById('mobile-menu-close');\n        const menuCards = document.querySelectorAll('.menu-card');\n        const menuLinks = document.querySelectorAll('.mobile-menu-link');\n        let isMenuOpen = false;\n\n        const menuTl = gsap.timeline({ paused: true, reversed: true });\n        menuTl\n            .to(menuOverlay, { autoAlpha: 1, duration: 0 })\n            .set(menuOverlay, { pointerEvents: \"auto\" })\n            .to(menuBackdrop, { opacity: 1, duration: 0.4, ease: \"power2.out\" })\n            .to(menuClose, { opacity: 1, y: 0, duration: 0.4, ease: \"back.out(1.7)\" }, \"-=0.2\")\n            .to(menuCards, { y: 0, opacity: 1, duration: 0.6, stagger: 0.08, ease: \"power3.out\" }, \"-=0.3\")\n            .from(menuLinks, { x: -20, opacity: 0, duration: 0.4, stagger: 0.05, ease: \"power2.out\" }, \"-=0.4\");\n\n        function toggleMenu() {\n            if (!isMenuOpen) {\n                menuTl.play();\n                document.body.style.overflow = 'hidden';\n            } else {\n                menuTl.reverse();\n                document.body.style.overflow = '';\n            }\n            isMenuOpen = !isMenuOpen;\n        }\n\n        if(menuBtn) menuBtn.addEventListener('click', toggleMenu);\n        if(menuClose) menuClose.addEventListener('click', toggleMenu);\n        if(menuOverlay) menuOverlay.addEventListener('click', (e) => { if (e.target === document.querySelector('#mobile-menu-overlay > div') && isMenuOpen) toggleMenu(); });\n        menuLinks.forEach(link => link.addEventListener('click', () => { if(isMenuOpen) toggleMenu(); }));\n\n        // --- CAROUSEL ARROWS LOGIC ---\n        const container = document.getElementById('screenshot-container');\n        const leftBtn = document.getElementById('scroll-left');\n        const rightBtn = document.getElementById('scroll-right');\n\n        if(container && leftBtn && rightBtn) {\n            leftBtn.addEventListener('click', () => {\n                container.scrollBy({ left: -340, behavior: 'smooth' });\n            });\n            rightBtn.addEventListener('click', () => {\n                container.scrollBy({ left: 340, behavior: 'smooth' });\n            });\n        }\n    });",
