  'charging-partners.html': {
    externalScripts: ['/js/script.js'],
    inlineScripts: [
      "// 1. Accordion Logic (Internal script for FAQ)\n  function toggleAccordion(element) {\n    const content = element.querySelector('.accordion-content');\n    const icon = element.querySelector('.bi-plus-lg');\n\n    // Close others\n    document.querySelectorAll('.accordion-content').forEach(acc => {\n      if (acc !== content) {\n        acc.classList.remove('grid-rows-[1fr]');\n        acc.classList.add('grid-rows-[0fr]');\n        acc.parentElement.querySelector('.bi-plus-lg').style.transform = 'rotate(0deg)';\n        acc.parentElement.querySelector('.bi-plus-lg').classList.remove('text-white');\n        acc.parentElement.querySelector('.bi-plus-lg').classList.add('text-emerald-500');\n      }\n    });\n\n    // Toggle current\n    if (content.classList.contains('grid-rows-[1fr]')) {\n      content.classList.remove('grid-rows-[1fr]');\n      content.classList.add('grid-rows-[0fr]');\n      icon.style.transform = 'rotate(0deg)';\n      icon.classList.add('text-emerald-500');\n      icon.classList.remove('text-white');\n    } else {\n      content.classList.remove('grid-rows-[0fr]');\n      content.classList.add('grid-rows-[1fr]');\n      icon.style.transform = 'rotate(45deg)';\n      icon.classList.remove('text-emerald-500');\n      icon.classList.add('text-white');\n    }\n  }\n\n  // 2. Solar Logic\n  const solarOptionGroup = document.getElementById('solar-option-group');\n  const solarCapacityContainer = document.getElementById('solar-capacity-container');\n  const solarCapacityInput = document.getElementById('solar-capacity');\n\n  if (solarOptionGroup) {\n    solarOptionGroup.addEventListener('change', (event) => {\n      if (event.target.name === 'solar-option') {\n        if (event.target.value === 'Yes') {\n          solarCapacityContainer.style.maxHeight = '100px';\n          solarCapacityContainer.style.opacity = '1';\n          solarCapacityInput.required = true;\n        } else {\n          solarCapacityContainer.style.maxHeight = '0';\n          solarCapacityContainer.style.opacity = '0';\n          solarCapacityInput.required = false;\n          solarCapacityInput.value = '';\n        }\n      }\n    });\n  }\n\n  // 3. Form Logic\n  const form = document.getElementById('partner-form');\n  const successMessage = document.getElementById('success-message');\n  const errorMessage = document.getElementById('error-message');\n  const submitButton = document.getElementById('submit-button');\n\n  if (form) {\n    form.addEventListener('submit', function(event) {\n      event.preventDefault();\n      const formData = new FormData(form);\n      submitButton.disabled = true;\n      submitButton.innerHTML = '<span class=\"animate-pulse\">Sending...</span>';\n\n      fetch(form.action, {\n        method: 'POST',\n        body: formData,\n        headers: { 'Accept': 'application/json' }\n      }).then(response => {\n        if (response.ok) {\n          successMessage.classList.remove('hidden');\n          form.reset();\n        } else {\n          throw new Error('Failed');\n        }\n      }).catch(error => {\n        errorMessage.classList.remove('hidden');\n      }).finally(() => {\n        submitButton.disabled = false;\n        submitButton.innerHTML = `Submit Application <i class=\"bi bi-arrow-right group-hover:translate-x-1 transition-transform\"></i>`;\n      });\n    });\n  }",
    ],
  },
